   201→func Auth(options *AuthOptions) web.Handler {
   202→	return func(c *contextmodel.ReqContext) {
   203→		forceLogin := false
   204→		if c.AllowAnonymous {
   205→			forceLogin = shouldForceLogin(c)
   206→			if !forceLogin {
   207→				orgIDValue := c.Req.URL.Query().Get("orgId")
   208→				orgID, err := strconv.ParseInt(orgIDValue, 10, 64)
   209→				if err == nil && orgID > 0 && orgID != c.GetOrgID() {
   210→					forceLogin = true
   211→				}
   212→			}
   213→		}
   214→
   215→		requireLogin := !c.AllowAnonymous || forceLogin || options.ReqNoAnonynmous
   216→
   217→		if !c.IsSignedIn && options.ReqSignedIn && requireLogin {
   218→			var revokedErr *auth.TokenRevokedError
   219→			if errors.As(c.LookupTokenErr, &revokedErr) {
   220→				tokenRevoked(c, revokedErr)
   221→				return
   222→			}
   223→
   224→			notAuthorized(c)
   225→			return
   226→		}
   227→
   228→		if !c.IsGrafanaAdmin && options.ReqGrafanaAdmin {
   229→			accessForbidden(c)
